func NewManager(
	ctx context.Context,
	clientCfg *v1.ClientCommonConfig,
	msgTransporter transport.MessageTransporter,
) *Manager {
	return &Manager{
		proxies:	make(map[string]*Wrapper),
		msgTransporter:	msgTransporter,
		closed:		false,
		clientCfg:	clientCfg,
		ctx:		ctx,
	}
}
